import requests
from bs4 import BeautifulSoup

# Define the URL of the article
article_url = "https://www.science.org/doi/10.1126/sciadv.abf1694"

# Set a realistic User-Agent header to mimic a browser request
headers = {
    "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/115.0.0.0 Safari/537.36"
}

try:
    # Send GET request to the article URL with headers
    response = requests.get(article_url, headers=headers)
    response.raise_for_status()  # Raise an exception for HTTP errors

    # Parse the HTML content using BeautifulSoup
    soup = BeautifulSoup(response.text, 'html.parser')

    # Locate the abstract section - typically inside a <div> with class 'abstract' or similar
    abstract_section = soup.find('div', class_='abstract')
    if not abstract_section:
        abstract_section = soup.find('section', class_='abstract')
    if not abstract_section:
        abstract_section = soup.find('div', {'id': 'abstract'})

    # Extract text if abstract section is found
    if abstract_section:
        abstract_text = abstract_section.get_text(strip=True)
        print("Abstract:")
        print(abstract_text)
    else:
        print("Abstract section not found in the page.")

except requests.exceptions.HTTPError as http_err:
    print(f"HTTP error occurred: {http_err}")
except requests.exceptions.ConnectionError as conn_err:
    print(f"Connection error occurred: {conn_err}")
except requests.exceptions.Timeout as timeout_err:
    print(f"Timeout error occurred: {timeout_err}")
except requests.exceptions.RequestException as req_err:
    print(f"An error occurred while fetching the page: {req_err}")
except Exception as e:
    print(f"An unexpected error occurred: {e}")
